#include <bits/stdc++.h>
using namespace std;

const int N=1e6+6;

int t,n,a[N],l[N],r[N],p[N];

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            scanf("%d",&a[i]);
            p[a[i]]=i;
        }
        int ans=abs(a[n]-a[1])+n;
        l[1]=1e9;
        for(int i=2;i<=n-2;i++)
            l[i]=min(l[i-1],abs(a[i]-a[1]));
        r[n]=1e9;
        for(int i=n-1;i>2;i--)
            r[i]=min(r[i+1],abs(a[i]-a[n]));
        for(int i=2;i<n-1;i++){
            ans=min(ans,l[i]+r[i+1]+n+2);
            ans=min(ans,abs(a[i]-a[1])+abs(a[i+1]-a[n])+n);
            if(p[a[i+1]+1]<n-1 && a[i+1]<n && p[a[i+1]+1]>i)
                ans=min(ans,abs(a[i]-a[1])+abs(a[p[a[i+1]+1]+1]-a[n])+n+1);
            if(p[a[i+1]-1]<n-1 && a[i+1]>1 && p[a[i+1]-1]>i)
                ans=min(ans,abs(a[i]-a[1])+abs(a[p[a[i+1]-1]+1]-a[n])+n+1);
        }
        printf("%d\n",ans);
    }
    return 0;
}
